SELECT [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].No_, Val([Direct Unit Cost]) AS PurchasePrice, [Purch_ Price Model Item].[Currency Code], [netamount]/[pairssold] AS [Net Price], [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].[Trademark Code], [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].[Collection Code], [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].[Line Code], [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].[Season Code], IIf([currency code]="USD",Val([Direct Unit Cost])/1.25,Val([Direct Unit Cost])) AS PurchasePriceEuro, [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].PairsSold, [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].NetAmount
FROM [Purch_ Price Model Item] INNER JOIN [zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo] ON [Purch_ Price Model Item].[Model Item No_]=[zz-help-qVend-DeterminazionePrezzoMedioNetto-zz-Costo].No_;

